export default {
components: { NavBar },
  // 健康数据存储
  data: {
    bloodPressure: "120/80",
    bloodSugar: 5.2,
    weight: 65,
    height: 170,
    steps: 8560,
    lastUpdate: "2023-06-15 08:30",
    weightStatus: "normal"
  },

  // 获取健康数据
  getHealthData() {
    return this.data;
  },

  // 更新体重数据
  updateWeight(newWeight) {
    this.data.weight = newWeight;
    this.data.lastUpdate = new Date().toLocaleDateString();
    // 更新 weightStatus
    const bmi = this.data.weight / Math.pow(this.data.height / 100, 2);
    if (bmi < 18.5) this.data.weightStatus = "underweight";
    else if (bmi < 24) this.data.weightStatus = "normal";
    else if (bmi < 28) this.data.weightStatus = "overweight";
    else this.data.weightStatus = "obese";
  },

  // 更新步数数据
  updateSteps(newSteps) {
    this.data.steps = newSteps;
    this.data.lastUpdate = new Date().toLocaleDateString();
  },

  // 血压参考值
  bloodPressureRanges: {
    systolic: { low: "<90", normal: "90-140" },
    diastolic: { low: "<60", normal: "60-90" }
  },

  // 血糖参考值 (corrected to match component expectations)
  bloodSugarRanges: {
    fasting: { normal: "3.9-6.1" },
    postprandial: { normal: "<7.8" }
  },

  // 步数目标
  stepGoal: 10000
};